import uos as os
from microcoapy import MicroCoAP, Resource

# Create a CoAP server instance
server = MicroCoAP()

# Define resources
class TempSensorResource(Resource):
    def render_get(self, env, data):
        return "Temperature: 25C".encode('utf-8')

class LightActuatorResource(Resource):
    def render_put(self, env, data):
        if b"ON" in data:
            print("Turning light on")
        elif b"OFF" in data:
            print("Turning light off")
        else:
            return "Invalid request"
        return ""

# Add resources to the server
server.add_resource('/.well-known/core', lambda env, data: """<?xml version="1.0"?>
<mgmt:management xmlns:mgt="urn:draft-koster-iot-architecture-management"/>
</request>""".encode('utf-8'))
server.add_resource('/sensors/temp', TempSensorResource())
server.add_resource('/actuators/light', LightActuatorResource())

# Set up the server
server.listen(5683)
print("CoAP Server listening on port 5683")